// // This module decodes an address to select between two 16-bit values. When the address is 0, it outputs a 16-bit HIGH signal; when the address is 1, it outputs a 16-bit LOW signal.
module top_module(
    input [0:0] address,
    input clock,
    output reg [15:0] q
);always @(posedge clock) begin
    if (address == 1'b0) begin
        q <= 16'b0000000000000000;
    end else if (address == 1'b1) begin
        q <= 16'b1111111111111111;
    end
end

endmodule
